SELECT COUNT(DISTINCT LPP.FK_PRODBIB) AS QUANTIDADE FROM LATTES_P_PRODBIB LPP JOIN LATTES_PRODBIB LPB ON LPB.PK = LPP.FK_PRODBIB JOIN SERVIDOR S ON S.PK_SIAPE = LPP.FK_SIAPE WHERE LOWER(LPB.TIPO) = 'trabalho em evento' AND LOWER(LPB.NATUREZA) = 'completo' AND LPB.ANO = '2024' AND LOWER(S.SIGLA_CAMPUS) = 'apa' AND LOWER(COALESCE(S.AREA_INGRESSO, '')) LIKE '%artes%'